FictionBook.stylesheet:
body[name=""] > title p {font-size:200%; margin-bottom:1em}
body[name=""] > section title p {font-weight:bold;page-break-before:always}
annotation p, title+p, subtitle+p, poem+p, p[style="p0"] {text-indent:0px}
poem {font-style: normal; font-size:90%; margin-left:9%; margin-top:0em; margin-bottom:0em;}
p {word-spacing:0.4em;}
p[style="sign"], p[style="addr"] {margin-left: 30%; text-align: right; page-break-before: avoid}
p[style="addr"] {font-style: italic; page-break-after:avoid;}
text-author {font-style: italic}
